static uint64_t rng=1;static uint32_t rnd(void){rng=rng*6364136223846793005ULL+1;return (uint32_t)(rng>>32);}static void fill16(uint16_t*x,size_t n,uint64_t seed){rng=seed;for(size_t i=0;i<n;i++)x[i]=(uint16_t)rnd();}static void fill8(uint8_t*x,size_t n,uint64_t seed){rng=seed;for(size_t i=0;i<n;i++)x[i]=(uint8_t)rnd();}static uint64_t sum16(uint16_t*x,size_t n){uint64_t s=0;for(size_t i=0;i<n;i++)s=s*1315423911u+x[i];return s;}
static void runone(const char*ps,const sdat_table*orig,const sdat_table*sda,size_t n,int avx,int sda_path,int rep){uint16_t *words=malloc(n*2);uint16_t *out=malloc(n*2);size_t buflen=n*8+4096;uint8_t*buf=malloc(buflen);sdat_stats st={0};fill16(words,n,1234+rep);fill8(buf,buflen,5678+rep);unsigned long long c0,c1;int rc=0;if(!sda_path){c0=cyc();rc=avx?frodo_original_sample_n_avx2(words,n,orig):frodo_original_sample_n(words,n,orig);c1=cyc();}else{sdat_bitreader br;sdat_bitreader_init(&br,buf,buflen);c0=cyc();rc=avx?frodo_sda_sample_n_avx2(out,n,&br,sda,&st):frodo_sda_sample_n(out,n,&br,sda,&st);c1=cyc();memcpy(words,out,n*2);}double cps=(double)(c1-c0)/(double)(n?n:1);double expacc=sda_path?(double)sda->denominator_u64/(double)(1u<<sda->random_draw_bits):1.0;double obs=sda_path&&st.attempts?(double)n/(double)st.attempts:1.0;printf("Frodo,%s,%s,%s,%zu,%d,%llu,%.3f,0," ,ps,sda_path?(avx?"sda-sample-n-avx2":"sda-sample-n-scalar"):(avx?"official-original-avx2":"official-original-scalar"),"sample_n-core",n,rep,(unsigned long long)(c1-c0),cps);printf("%llu,%llu,%llu,%llu,%.9f,%.9f,%llu,%llu,unknown,-O3,",(unsigned long long)(sda_path?st.random_bits-(uint64_t)n:15*n),(unsigned long long)(sda_path?n:1*n),(unsigned long long)st.rejections,(unsigned long long)(sda_path?st.attempts:n),expacc,obs,(unsigned long long)st.random_bytes,(unsigned long long)sum16(words,n));printf("%s,%s\n",avx?"avx2":"scalar",rc?"error":"ok");free(words);free(out);free(buf);} 
